  // (select c, a, b) fadd (select c, b, a) => a fadd b.
  // When both selects have the same condition and swapped operands,
  // the result of fadd is always a fadd b due to commutativity.
  if (auto *Sel0 = dyn_cast<SelectInst>(Op0)) {
    if (auto *Sel1 = dyn_cast<SelectInst>(Op1)) {
      if (Sel0->getCondition() == Sel1->getCondition()) {
        if (Sel0->getTrueValue() == Sel1->getFalseValue() &&
            Sel0->getFalseValue() == Sel1->getTrueValue()) {
          return BinaryOperator::CreateWithCopiedFlags(
              Instruction::FAdd, Sel0->getTrueValue(), Sel0->getFalseValue(), &I);
        }
      }
    }
  }

